// With async/await
async function loadUser(id: number): Promise<User> {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.json();
  } catch (err) {
    console.error('Failed to load user:', err);
    throw err;   // re-throw so the caller knows
  } finally {
    hideSpinner();   // always hide, regardless of outcome
  }
}

// Custom error classes — recommended for domain errors
class ApiError extends Error {
  constructor(
    public readonly status: number,
    message: string,
    public readonly body?: unknown,
  ) {
    super(message);
    this.name = 'ApiError';
  }
}

class ValidationError extends Error {
  constructor(
    public readonly field: string,
    message: string,
  ) {
    super(message);
    this.name = 'ValidationError';
  }
}

// Usage
async function fetchUser(id: number): Promise<User> {
  const res = await fetch(`/api/users/${id}`);
  if (!res.ok) {
    const body = await res.json().catch(() => null);
    throw new ApiError(res.status, res.statusText, body);
  }
  return res.json();
}

async function handleRequest(id: number) {
  try {
    const user = await fetchUser(id);
    return user;
  } catch (err) {
    if (err instanceof ApiError) {
      if (err.status === 404) return null;   // not found — acceptable
      if (err.status === 401) {
        await refreshToken();
        return fetchUser(id);                // retry after refresh
      }
      throw err;   // other HTTP errors — propagate
    }

    if (err instanceof TypeError) {
      // Network failure (fetch throws TypeError for network errors)
      console.warn('Network unavailable, returning cached data');
      return getCachedUser(id);
    }

    if ((err as DOMException).name === 'AbortError') {
      return null;   // request was cancelled — not an error
    }

    throw err;   // unknown error — re-throw
  }
}

// Anti-pattern: silently swallowing
try {
  await riskyOperation();
} catch {}   // error disappears — debugging nightmare

// Anti-pattern: losing the original error
try {
  await riskyOperation();
} catch {
  throw new Error('Operation failed');   // original stack trace gone
}

// Correct: wrap with cause (ES2022)
try {
  await riskyOperation();
} catch (err) {
  throw new Error('Operation failed', { cause: err });
  // err.cause preserves the original error and stack
}

// Correct: log then re-throw
try {
  await riskyOperation();
} catch (err) {
  logger.error('riskyOperation failed', { err, context });
  throw err;   // caller still sees the original error
}

// Error propagates through the call chain
async function step3(): Promise<void> {
  throw new Error('step3 failed');
}

async function step2(): Promise<void> {
  await step3();   // rejection propagates
}

async function step1(): Promise<void> {
  await step2();   // rejection propagates
}

// Caught at the top
async function run() {
  try {
    await step1();
  } catch (err) {
    console.error('Caught at run():', err.message);   // 'step3 failed'
  }
}

// Parallel operations — Promise.all rejects on first failure
async function parallel() {
  try {
    const [a, b, c] = await Promise.all([stepA(), stepB(), stepC()]);
  } catch (err) {
    // one of stepA/B/C rejected — which one?
    // Use allSettled for individual error handling
  }
}

// allSettled — inspect each result
async function parallelSafe() {
  const results = await Promise.allSettled([stepA(), stepB(), stepC()]);
  for (const result of results) {
    if (result.status === 'rejected') {
      console.error('A step failed:', result.reason);
    }
  }
}

async function withConnection<T>(fn: (conn: Connection) => Promise<T>): Promise<T> {
  const conn = await openConnection();
  try {
    return await fn(conn);
  } finally {
    await conn.close();   // always closes, even if fn throws
  }
}

