import { ErrorHandler, Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';

@Injectable()
export class GlobalErrorHandler implements ErrorHandler {
  private http = inject(HttpClient);

  handleError(error: unknown): void {
    const message = error instanceof Error ? error.message : String(error);
    const stack    = error instanceof Error ? error.stack   : undefined;

    console.error('Unhandled error:', error);

    // Send to error monitoring (fire-and-forget)
    this.http.post('/api/errors', { message, stack }).subscribe({
      error: () => {}  // ignore reporting failures
    });
  }
}

// Register in app.config.ts
export const appConfig: ApplicationConfig = {
  providers: [
    { provide: ErrorHandler, useClass: GlobalErrorHandler },
  ],
};

// Browser event for unhandled Promise rejections
window.addEventListener('unhandledrejection', (event) => {
  console.error('Unhandled rejection:', event.reason);
  event.preventDefault();   // suppress default console error
  reportToMonitoring(event.reason);
});

// Angular HttpClient error interceptor
@Injectable()
export class ErrorInterceptor implements HttpInterceptor {
  intercept(req: HttpRequest<unknown>, next: HttpHandler): Observable<HttpEvent<unknown>> {
    return next.handle(req).pipe(
      catchError((err: HttpErrorResponse) => {
        if (err.status === 401) redirectToLogin();
        if (err.status >= 500) reportToMonitoring(err);
        return throwError(() => err);
      })
    );
  }
}

describe('fetchUser error handling', () => {
  let http: HttpTestingController;

  beforeEach(() => {
    TestBed.configureTestingModule({
      providers: [provideHttpClient(), provideHttpClientTesting()],
    });
    http = TestBed.inject(HttpTestingController);
  });

  it('throws ApiError on 404', async () => {
    const service = TestBed.inject(UserService);
    const promise = service.getUser(999);

    http.expectOne('/api/users/999')
      .flush('Not found', { status: 404, statusText: 'Not Found' });

    await expectAsync(promise)
      .toBeRejectedWith(jasmine.objectContaining({ status: 404 }));
  });

  it('returns null for 404 after handleRequest recovery', async () => {
    spyOn(service, 'getUser').and.rejectWith(new ApiError(404, 'Not Found'));
    const result = await handleRequest(999);
    expect(result).toBeNull();
  });
});

