// Promise.any throws AggregateError if all reject
async function fetchFromMirrors(urls: string[]) {
  try {
    return await Promise.any(urls.map(url => fetch(url).then(r => r.json())));
  } catch (err) {
    if (err instanceof AggregateError) {
      console.error(`All ${err.errors.length} mirrors failed:`);
      err.errors.forEach((e, i) => console.error(`  [${i}] ${e.message}`));
    }
    throw err;
  }
}

// Constructing AggregateError manually for batch validation
function validateAll(items: unknown[]): void {
  const errors: Error[] = [];

  for (const item of items) {
    try {
      validate(item);
    } catch (err) {
      errors.push(err as Error);
    }
  }

  if (errors.length > 0) {
    throw new AggregateError(errors, `${errors.length} validation errors`);
  }
}

// Run multiple operations, collect all errors before throwing
async function processAll(ids: number[]): Promise<ProcessResult[]> {
  const results = await Promise.allSettled(ids.map(id => processItem(id)));

  const failures = results
    .filter((r): r is PromiseRejectedResult => r.status === 'rejected')
    .map(r => r.reason as Error);

  if (failures.length > 0) {
    throw new AggregateError(
      failures,
      `${failures.length} of ${ids.length} items failed to process`
    );
  }

  return (results as PromiseFulfilledResult<ProcessResult>[]).map(r => r.value);
}

// Structured logger interface
interface LogEntry {
  level: 'error' | 'warn' | 'info';
  message: string;
  error?: { name: string; message: string; stack?: string; cause?: unknown };
  context?: Record<string, unknown>;
  timestamp: string;
}

function toLogEntry(err: unknown, context?: Record<string, unknown>): LogEntry {
  const error = err instanceof Error
    ? { name: err.name, message: err.message, stack: err.stack, cause: (err as Error & { cause?: unknown }).cause }
    : { name: 'UnknownError', message: String(err) };

  return {
    level: 'error',
    message: error.message,
    error,
    context,
    timestamp: new Date().toISOString(),
  };
}

// Angular service usage
@Injectable({ providedIn: 'root' })
export class LoggingService {
  private http = inject(HttpClient);

  logError(err: unknown, context?: Record<string, unknown>): void {
    const entry = toLogEntry(err, context);
    console.error(entry);                                // local dev
    this.http.post('/api/logs', entry).subscribe();     // remote collection
  }
}

// Component using structured logging
@Component({ ... })
export class CheckoutComponent {
  private log = inject(LoggingService);
  private orderId?: string;

  async submitOrder(cart: Cart) {
    try {
      const order = await this.orderService.place(cart);
      this.orderId = order.id;
    } catch (err) {
      this.log.logError(err, {
        component: 'CheckoutComponent',
        userId: this.authService.userId,
        cartItemCount: cart.items.length,
      });
      this.errorMessage = 'Order failed. Please try again.';
    }
  }
}
